mapper.select:
SELECT COUNT(1) FROM patients p WHERE 1 = 1
AND p.hospital_id = #{hospitalId}
AND p.is_active = 1

SELECT COUNT(1) FROM pacs_studies s WHERE 1 = 1
AND s.hospital_id = #{hospitalId}
AND s.is_active = 1

SELECT COUNT(1) FROM hospital_dicom_servers s WHERE 1 = 1
AND s.hospital_id = #{hospitalId}
AND s.is_active != 2

SELECT COUNT(1) FROM hospital_dicom_servers s WHERE 1 = 1
AND s.hospital_id = #{hospitalId}
AND s.is_active = 1

SELECT COUNT(1) FROM hospital_dicom_servers s WHERE 1 = 1
AND s.hospital_id = #{hospitalId}
AND s.is_active != 1 AND s.is_active != 2

SELECT COUNT(DISTINCT hm.modality_id) FROM hospital_modalities hm WHERE 1 = 1
AND hm.hospital_id = #{hospitalId}
AND hm.is_active = 1 AND EXISTS ( SELECT 1 FROM hospital_modality_server_routes r WHERE r.hospital_id = hm.hospital_id AND r.modality_id = hm.modality_id AND r.is_active = 1 )

SELECT COUNT(1) FROM hospital_modalities hm WHERE 1 = 1
AND hm.hospital_id = #{hospitalId}
AND hm.is_active = 1 AND NOT EXISTS ( SELECT 1 FROM hospital_modality_server_routes r WHERE r.hospital_id = hm.hospital_id AND r.modality_id = hm.modality_id AND r.is_active = 1 )

SELECT CASE UPPER(CAST(q.status AS TEXT)) WHEN '1' THEN 1 WHEN 'WAITING' THEN 1 WHEN '2' THEN 2 WHEN 'IN_PROGRESS' THEN 2 WHEN '3' THEN 3 WHEN 'CANCELLED' THEN 3 WHEN '4' THEN 4 WHEN 'FAILED' THEN 4 ELSE NULL END AS statusCode, COUNT(1) AS total FROM pacs_worklists q WHERE 1 = 1
AND q.hospital_id = #{hospitalId}
GROUP BY CASE UPPER(CAST(q.status AS TEXT)) WHEN '1' THEN 1 WHEN 'WAITING' THEN 1 WHEN '2' THEN 2 WHEN 'IN_PROGRESS' THEN 2 WHEN '3' THEN 3 WHEN 'CANCELLED' THEN 3 WHEN '4' THEN 4 WHEN 'FAILED' THEN 4 ELSE NULL END

SELECT COUNT(1) FROM pacs_worklists q WHERE 1 = 1
AND q.hospital_id = #{hospitalId}
AND UPPER(CAST(q.status AS TEXT)) IN ('1', 'WAITING') AND COALESCE(q.created_at, q.created, NOW()) <= (NOW() - (#{thresholdMinutes} * INTERVAL '1 minute'))

SELECT COUNT(1) FROM pacs_worklists q WHERE 1 = 1
AND q.hospital_id = #{hospitalId}
AND DATE(COALESCE(q.created_at, q.created, NOW())) = CURRENT_DATE

SELECT COUNT(1) FROM pacs_worklist_histories h WHERE 1 = 1
AND h.hospital_id = #{hospitalId}
AND UPPER(CAST(h.to_status AS TEXT)) IN ('3', 'CANCELLED') AND DATE(COALESCE(h.created, NOW())) = CURRENT_DATE

SELECT q.public_id::text AS publicKey, q.visit_code AS visitCode, NULLIF(TRIM(CONCAT(COALESCE(p.first_name, ''), ' ', COALESCE(p.last_name, ''))), '') AS patientName, AS status FROM pacs_worklists q INNER JOIN patients p ON p.id = q.patient_id WHERE 1 = 1
AND q.hospital_id = #{hospitalId}
ORDER BY COALESCE(q.modified_at, q.created_at, q.created) DESC, q.id DESC LIMIT #{limit}
